  // FAQ items
  "faqp.q1": { tr: "SahteAvcı tam olarak ne yapar?", en: "What exactly does SahteAvcı do?" },
  "faqp.a1": { tr: "SahteAvcı, Trendyol ve Hepsiburada gibi pazaryerlerinde şüpheli listingleri daha hızlı tespit etmeye, delil akışını düzenlemeye ve şikayet operasyonunu kolaylaştırmaya yardımcı olur.", en: "SahteAvcı helps detect suspicious listings on marketplaces like Trendyol and Hepsiburada faster, organize evidence workflows, and streamline the complaint process." },
  "faqp.q2": { tr: "Kimler için uygundur?", en: "Who is it suitable for?" },
  "faqp.a2": { tr: "Özellikle küçük ve orta ölçekli marka sahipleri, pazaryeri ekipleri, marka yöneticileri ve fikri mülkiyet danışmanları için uygundur.", en: "It's especially suitable for small and mid-size brand owners, marketplace teams, brand managers, and IP consultants." },
  "faqp.q3": { tr: "Tescilli marka gerekli mi?", en: "Is a registered trademark required?" },
  "faqp.a3": { tr: "Hayır. Anahtar kelime ve marka adıyla da takip yapılabilir. Ancak tescilli marka, resmi şikayet süreçlerinde önemli avantaj sağlayabilir.", en: "No. You can also track by keyword and brand name. However, a registered trademark can provide significant advantages in official complaint processes." },
  "faqp.q4": { tr: "Hangi pazaryerlerine odaklanır?", en: "Which marketplaces does it focus on?" },
  "faqp.a4": { tr: "Ana odak Trendyol ve Hepsiburada'dır. Kapsam ileride genişletilebilir.", en: "The primary focus is Trendyol and Hepsiburada. Coverage may expand in the future." },
  "faqp.q5": { tr: "Ücretsiz plan gerçekten ücretsiz mi?", en: "Is the free plan really free?" },
  "faqp.a5": { tr: "Evet, temel kullanım için ücretsiz başlangıç planı sunulur.", en: "Yes, a free starter plan is offered for basic use." },
  "faqp.q6": { tr: "Planımı daha sonra yükseltebilir miyim?", en: "Can I upgrade my plan later?" },
  "faqp.a6": { tr: "Evet, ihtiyaç arttıkça üst planlara geçiş kurgulanabilir.", en: "Yes, you can upgrade to higher plans as your needs grow." },
  "faqp.q7": { tr: "Taksitli ödeme var mı?", en: "Is installment payment available?" },
  "faqp.a7": { tr: "Ücretli planlar için taksitli ödeme desteği sunulması hedeflenmektedir. Nihai ödeme koşulları satın alma aşamasında gösterilir.", en: "Installment payment support is planned for paid plans. Final payment terms will be shown at checkout." },
  "faqp.q8": { tr: "Kurumsal veya özel fiyatlandırma mümkün mü?", en: "Is custom or enterprise pricing available?" },
  "faqp.a8": { tr: "Özel ihtiyaçlar için iletişim üzerinden değerlendirme yapılabilir.", en: "Custom needs can be evaluated through direct contact." },
  "faqp.q9": { tr: "Kurulum ne kadar sürer?", en: "How long does setup take?" },
  "faqp.a9": { tr: "Kurulum genellikle birkaç dakika içinde tamamlanır.", en: "Setup is typically completed within a few minutes." },
  "faqp.q10": { tr: "Teknik bilgi gerekir mi?", en: "Is technical knowledge required?" },
  "faqp.a10": { tr: "Hayır. Ürün, günlük operasyon akışına yakın ve anlaşılır olacak şekilde tasarlanır.", en: "No. The product is designed to be intuitive and close to everyday operational workflows." },
  "faqp.q11": { tr: "Veriler dışa aktarılabiliyor mu?", en: "Can data be exported?" },
  "faqp.a11": { tr: "Plan seviyesine bağlı olarak dışa aktarım seçenekleri sunulabilir.", en: "Export options may be available depending on the plan level." },
  "faqp.q12": { tr: "Görsel analiz tüm planlarda var mı?", en: "Is visual analysis available on all plans?" },
  "faqp.a12": { tr: "Bazı gelişmiş analiz özellikleri yalnızca üst planlarda yer alabilir.", en: "Some advanced analysis features may only be available on higher plans." },
  "faqp.q13": { tr: "Eklenti güvenli mi?", en: "Is the extension secure?" },
  "faqp.a13": { tr: "Güvenlik ve veri minimizasyonu temel öncelikler arasındadır.", en: "Security and data minimization are among the core priorities." },
  "faqp.q14": { tr: "Verilerim nasıl işlenir?", en: "How is my data processed?" },
  "faqp.a14": { tr: "Mimari mümkün olduğunca yerel işleme yaklaşımına dayanır.", en: "The architecture relies on local processing as much as possible." },
  "faqp.q15": { tr: "KVKK ile ilgili taleplerimi nasıl iletebilirim?", en: "How can I submit KVKK-related requests?" },
  "faqp.a15": { tr: "KVKK ve veri talepleri için destek e-posta adresi üzerinden iletişime geçebilirsiniz.", en: "You can contact us via the support email for KVKK and data requests." },
  "faqp.q16": { tr: "Tüm işlem tamamen yerel mi?", en: "Is all processing fully local?" },
  "faqp.a16": { tr: "Ürün mümkün olduğunca tarayıcı içi işleme mantığıyla kurgulanır. Nihai teknik çerçeve ilgili belgelerde ayrıca netleştirilebilir.", en: "The product is designed with in-browser processing logic as much as possible. The final technical framework can be further clarified in related documents." },
  "faqp.q17": { tr: "Şikayet metinleri otomatik oluşuyor mu?", en: "Are complaint texts generated automatically?" },
  "faqp.a17": { tr: "Hazır şablonlar sayesinde şikayet süreci daha hızlı ve düzenli hale getirilebilir.", en: "Ready-made templates help make the complaint process faster and more organized." },
  "faqp.q18": { tr: "Bu araç hukuki danışmanlık yerine geçer mi?", en: "Does this tool replace legal advice?" },
  "faqp.a18": { tr: "Hayır. SahteAvcı operasyonel kolaylık sağlar; hukuki değerlendirme gereken durumlarda uzman görüşü ayrıca gerekebilir.", en: "No. SahteAvcı provides operational convenience; expert legal advice may still be needed for legal assessments." },
  "faqp.q19": { tr: "Toplanan kayıtlar doğrudan mahkemede kullanılabilir mi?", en: "Can collected records be used directly in court?" },
  "faqp.a19": { tr: "Kayıtlar delil düzeni açısından yardımcı olabilir; ancak hukuki kullanılabilirlik somut olaya göre değerlendirilmelidir.", en: "Records can be helpful for evidence organization, but legal admissibility should be evaluated on a case-by-case basis." },
  "faqp.q20": { tr: "Final yasal belgeler nerede?", en: "Where are the final legal documents?" },
  "faqp.a20": { tr: "Yasal sayfalar hazırlanma sürecindedir ve nihai metinler ayrıca güncellenecektir.", en: "Legal pages are being prepared and final texts will be updated separately." },

