  // ==================== FEATURES PAGE ====================
  "featp.pill": { tr: "Detaylı Özellikler", en: "Detailed Features" },
  "featp.title.1": { tr: "Sahte Ürün Tespiti İçin Geliştirilmiş ", en: "Advanced " },
  "featp.title.highlight": { tr: "Pratik Araçlar", en: "Practical Tools" },
  "featp.title.2": { tr: "", en: " for Counterfeit Detection" },
  "featp.subtitle": { tr: "SahteAvcı, Türk pazaryerlerinde marka ihlallerini daha görünür, daha düzenli ve daha yönetilebilir hale getirmek için tasarlanmıştır.", en: "SahteAvcı is designed to make brand infringements on Turkish marketplaces more visible, organized, and manageable." },
  "featp.prices": { tr: "Fiyatları İncele", en: "View Pricing" },
  "featp.anchor.arama": { tr: "Arama", en: "Search" },
  "featp.anchor.analiz": { tr: "Analiz", en: "Analysis" },
  "featp.anchor.gorsel": { tr: "Görsel", en: "Visual" },
  "featp.anchor.delil": { tr: "Delil", en: "Evidence" },
  "featp.anchor.sikayet": { tr: "Şikayet", en: "Complaint" },
  "featp.anchor.gizlilik": { tr: "Gizlilik", en: "Privacy" },
  "featp.anchor.senaryolar": { tr: "Kullanım Senaryoları", en: "Use Cases" },
  "featp.cap1.title": { tr: "Akıllı Arama ve Varyasyon Yakalama", en: "Smart Search and Variation Detection" },
  "featp.cap1.body": { tr: "SahteAvcı yalnızca birebir eşleşmeleri değil, isim varyasyonlarını, Türk pazaryerlerine özgü ifade kalıplarını ve yanıltıcı anahtar kelime kombinasyonlarını da görünür kılmayı hedefler.", en: "SahteAvcı aims to surface not just exact matches, but name variations, Turkish marketplace-specific expression patterns, and misleading keyword combinations." },
  "featp.cap1.b1": { tr: "Marka adı + anahtar kelime kombinasyonları", en: "Brand name + keyword combinations" },
  "featp.cap1.b2": { tr: "Türkçe sahtecilik jargonu farkındalığı", en: "Turkish counterfeit jargon awareness" },
  "featp.cap1.b3": { tr: "Şüpheli isim varyasyonlarını görünür kılma", en: "Surfacing suspicious name variations" },
  "featp.cap2.title": { tr: "Fiyat ve Listeleme Davranışı Üzerinden Risk Sinyalleri", en: "Risk Signals from Pricing and Listing Behavior" },
  "featp.cap2.body": { tr: "Olağandışı düşük fiyatlar ve şüpheli listeleme davranışları, ekiplerin hangi sonuçları öncelikli inceleyeceğini belirlemesine yardımcı olabilir.", en: "Unusually low prices and suspicious listing behavior can help teams determine which results to prioritize." },
  "featp.cap2.b1": { tr: "Düşük fiyat sinyalleri", en: "Low price signals" },
  "featp.cap2.b2": { tr: "Öncelikli inceleme mantığı", en: "Priority review logic" },
  "featp.cap2.b3": { tr: "Operasyonel zaman tasarrufu", en: "Operational time savings" },
  "featp.cap3.title": { tr: "Görsel Benzerlik Kontrolü ile Daha Geniş Tarama", en: "Broader Scanning with Visual Similarity Check" },
  "featp.cap3.body": { tr: "Görsel benzerlik desteği, yalnızca başlıktan fark edilmesi güç olan listingleri yüzeye çıkarmaya yardımcı olur.", en: "Visual similarity support helps surface listings that are hard to detect from titles alone." },
  "featp.cap3.b1": { tr: "Değiştirilmiş görsellerde benzerlik sinyali", en: "Similarity signals in modified images" },
  "featp.cap3.b2": { tr: "Manuel gözden kaçan sonuçları destekleme", en: "Catching results missed by manual review" },
  "featp.cap3.b3": { tr: "PRO planlarda genişletilmiş kullanım", en: "Extended usage on PRO plans" },
  "featp.cap4.title": { tr: "Delil Toplama ve Düzenli Kayıt Akışı", en: "Evidence Collection and Structured Record Flow" },
  "featp.cap4.body": { tr: "SahteAvcı, kullanıcıların listeleme detaylarını, ekran görüntülerini ve yapılandırılmış delilleri daha tutarlı şekilde toplamasına yardımcı olmayı amaçlar.", en: "SahteAvcı aims to help users collect listing details, screenshots, and structured evidence more consistently." },
  "featp.cap4.b1": { tr: "Ekran görüntüsü ve kayıt akışı", en: "Screenshot and record workflow" },
  "featp.cap4.b2": { tr: "Daha düzenli takip mantığı", en: "More organized tracking logic" },
  "featp.cap4.b3": { tr: "Dışa aktarım için hazırlık", en: "Preparation for export" },
  "featp.cap5.title": { tr: "Şikayet Şablonları ile Daha Hızlı Operasyon", en: "Faster Operations with Complaint Templates" },
  "featp.cap5.body": { tr: "Hazır şikayet şablonları, pazaryeri raporlama süreçleriyle uğraşan ekiplerin tekrarlı işlerini azaltmaya yardımcı olabilir.", en: "Ready-made complaint templates can help reduce repetitive work for teams dealing with marketplace reporting processes." },
  "featp.cap5.b1": { tr: "Hazır metin akışları", en: "Ready-made text workflows" },
  "featp.cap5.b2": { tr: "Operasyonel standardizasyon", en: "Operational standardization" },
  "featp.cap5.b3": { tr: "Tekrarlı işi azaltma", en: "Reducing repetitive work" },
  "featp.privacy.title": { tr: "Gizlilik ve Yerel İşleme Yaklaşımı", en: "Privacy and Local Processing Approach" },
  "featp.privacy.text": { tr: "SahteAvcı mimarisi, mümkün olduğunca tarayıcı içi ve veri minimizasyonu odaklı bir çalışma mantığına dayanır. Amaç, marka koruma iş akışını hızlandırırken güvenlik hassasiyetini korumaktır.", en: "SahteAvcı's architecture is based on in-browser and data-minimization-focused processing as much as possible. The goal is to speed up brand protection workflows while maintaining security sensitivity." },
  "featp.privacy.1": { tr: "Yerel işleme odaklı yaklaşım", en: "Local processing focused approach" },
  "featp.privacy.2": { tr: "Veri minimizasyonu", en: "Data minimization" },
  "featp.privacy.3": { tr: "Güvenlik önceliği", en: "Security priority" },
  "featp.usecases.title": { tr: "Kim Kullanıyor?", en: "Who Uses It?" },
  "featp.usecases.subtitle": { tr: "Farklı roller, farklı ihtiyaçlar — aynı pratik araç seti.", en: "Different roles, different needs — the same practical toolset." },
  "featp.uc1.title": { tr: "Küçük marka sahibi", en: "Small brand owner" },
  "featp.uc1.desc": { tr: "Kendi markasını pazaryerinde satan ve kopya satışları fark etmek isteyen girişimciler için temel tarama ve uyarı akışı.", en: "Basic scanning and alert workflows for entrepreneurs selling their own brand on marketplaces and wanting to spot counterfeits." },
  "featp.uc2.title": { tr: "Pazaryeri operasyon ekibi", en: "Marketplace operations team" },
  "featp.uc2.desc": { tr: "Birden fazla markayı aynı anda takip eden ekiplere düzenli tarama, dışa aktarım ve şikayet şablonları sunar.", en: "Offers structured scanning, exports, and complaint templates for teams tracking multiple brands simultaneously." },
  "featp.uc3.title": { tr: "Marka yöneticisi", en: "Brand manager" },
  "featp.uc3.desc": { tr: "Marka itibarını ve pazaryeri görünürlüğünü koruma sorumluluğu taşıyan yöneticiler için hızlı raporlama ve önceliklendirme.", en: "Fast reporting and prioritization for managers responsible for protecting brand reputation and marketplace visibility." },
  "featp.uc4.title": { tr: "IP danışmanı", en: "IP consultant" },
